// ── Sticker data ──────────────────────────────────────────────────────────────
const STICKERS = [
  { id: 1,  emoji: "🐱", label: "Cat" },
  { id: 2,  emoji: "🐶", label: "Dog" },
  { id: 3,  emoji: "🐼", label: "Panda" },
  { id: 4,  emoji: "🦊", label: "Fox" },
  { id: 5,  emoji: "🐸", label: "Frog" },
