];

// ── Virtual background options ─────────────────────────────────────────────────
const VBGS = [
  { id: "none",    label: "None",       style: {} },
  { id: "blur",    label: "Blur",       style: { filter: "blur(8px)" } },
  { id: "office",  label: "Office",     color: "#1a1a2e" },
